import{_ as a,o as s,c as r,ae as t}from"./chunks/framework.Czhw_PXq.js";const i="/images/hub_proposal_approve.png",o="/images/hub_analysis_review.png",v=JSON.parse('{"title":"Project & Analysis Approval","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user/approval.md","filePath":"guide/user/approval.md"}'),n={name:"guide/user/approval.md"};function l(p,e,c,d,h,g){return s(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="project-analysis-approval" tabindex="-1">Project &amp; Analysis Approval <a class="header-anchor" href="#project-analysis-approval" aria-label="Permalink to &quot;Project &amp; Analysis Approval&quot;">​</a></h1><p>Hub supports administrator approval workflows for projects and analyses. These ensure that federated computations are reviewed before execution.</p><h2 id="project-approval" tabindex="-1">Project Approval <a class="header-anchor" href="#project-approval" aria-label="Permalink to &quot;Project Approval&quot;">​</a></h2><p>Projects represent collaborative research efforts. When a user creates a project:</p><ol><li>The project enters a <strong>pending</strong> state</li><li>An administrator reviews the project details (description, risk assessment, data requirements, selected nodes)</li><li>The administrator <strong>approves</strong> or <strong>rejects</strong> the project</li><li>Only approved projects can have analyses created</li></ol><p><img src="'+i+'" alt="Project approval"></p><h2 id="analysis-approval" tabindex="-1">Analysis Approval <a class="header-anchor" href="#analysis-approval" aria-label="Permalink to &quot;Analysis Approval&quot;">​</a></h2><p>Analyses are distributed computations within a project. When a user submits an analysis for execution:</p><ol><li>The analysis enters a <strong>pending</strong> state</li><li>An administrator reviews the analysis configuration (code, selected nodes, master image)</li><li>The administrator <strong>approves</strong> or <strong>rejects</strong> the analysis</li><li>Approved analyses are queued for execution by the worker service</li></ol><p><img src="'+o+`" alt="Analysis review"></p><h2 id="analysis-execution-flow" tabindex="-1">Analysis Execution Flow <a class="header-anchor" href="#analysis-execution-flow" aria-label="Permalink to &quot;Analysis Execution Flow&quot;">​</a></h2><p>Once approved, an analysis goes through:</p><ol><li><strong>Build</strong> — the worker builds a Docker image from the analysis code and master image</li><li><strong>Configure</strong> — storage buckets are provisioned, configuration is locked</li><li><strong>Distribute</strong> — the container image is pushed to target node registries</li><li><strong>Execute</strong> — nodes pull and run the container against their local data</li><li><strong>Complete</strong> — results are collected and stored</li></ol><h2 id="skipping-approval-development" tabindex="-1">Skipping Approval (Development) <a class="header-anchor" href="#skipping-approval-development" aria-label="Permalink to &quot;Skipping Approval (Development)&quot;">​</a></h2><p>For development and testing, approval workflows can be disabled via environment variables on the <a href="/reference/core/">Core API</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SKIP_PROJECT_APPROVAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SKIP_ANALYSIS_APPROVAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Never disable approval workflows in production environments.</p></div>`,17)])])}const m=a(n,[["render",l]]);export{v as __pageData,m as default};
